def verify(answer):
    try:
        # Parse the answer as a list of integers
        roots = [int(x.strip()) for x in str(answer).split(",")]
    except Exception:
        return False

    # Define the polynomial
    x = Symbol('x')
    polynomial = x**4 + 5*x**3 + 9*x**2 - x - 14

    # Check if all provided roots satisfy the polynomial equation
    for root in roots:
        if polynomial.subs(x, root) != 0:
            return False

    # Check if there are no missing integer roots
    # Possible integer roots are divisors of the constant term (-14)
    constant_term = -14
    possible_roots = set()
    for d in range(1, abs(constant_term) + 1):
        if constant_term % d == 0:
            possible_roots.add(d)
            possible_roots.add(-d)

    # Verify all possible integer roots are accounted for
    actual_roots = [r for r in possible_roots if polynomial.subs(x, r) == 0]
    return set(roots) == set(actual_roots)

