def verify(answer):
    try:
        # Convert the answer to an integer defensively
        answer = int(str(answer).strip())
    except Exception:
        return False

    # Convert 629 to base 7 and base 8
    def to_base(n, base):
        digits = []
        while n > 0:
            digits.append(n % base)
            n //= base
        return set(digits)

    base7_digits = to_base(629, 7)
    base8_digits = to_base(629, 8)

    # Find the common digits
    common_digits = base7_digits & base8_digits

    # Verify the count of common digits matches the answer
    return answer == len(common_digits)

